12	const ResetPassword = () => {
13	  const navigate = useNavigate();
14	  const { toast } = useToast();
15	  const [password, setPassword] = useState("");
16	  const [confirmPassword, setConfirmPassword] = useState("");
17	  const [showPassword, setShowPassword] = useState(false);
18	  const [isLoading, setIsLoading] = useState(false);
19	  const [isRecovery, setIsRecovery] = useState(false);
20	  const [passwordErrors, setPasswordErrors] = useState<string[]>([]);
21	
22	  const validatePassword = (pwd: string): string[] => {
23	    const errors: string[] = [];
24	    if (pwd.length < 8) errors.push("At least 8 characters");
25	    if (!/[A-Z]/.test(pwd)) errors.push("One uppercase letter");
26	    if (!/[a-z]/.test(pwd)) errors.push("One lowercase letter");
27	    if (!/[0-9]/.test(pwd)) errors.push("One number");
28	    if (!/[^A-Za-z0-9]/.test(pwd)) errors.push("One special character");
29	    return errors;
30	  };
31	
32	  useEffect(() => {
33	    const { data: { subscription } } = supabase.auth.onAuthStateChange((event) => {
34	      if (event === "PASSWORD_RECOVERY") {
35	        setIsRecovery(true);
36	      }
37	    });
38	
39	    // Check hash for recovery token
40	    const hash = window.location.hash;
41	    if (hash && hash.includes("type=recovery")) {
42	      setIsRecovery(true);
43	    }
44	
45	    return () => subscription.unsubscribe();
46	  }, []);
47	
48	  const handlePasswordChange = (value: string) => {
49	    setPassword(value);
50	    setPasswordErrors(validatePassword(value));
51	  };
52	
53	  const handleSubmit = async (e: React.FormEvent) => {
54	    e.preventDefault();
55	
56	    const errors = validatePassword(password);
57	    if (errors.length > 0) {
58	      setPasswordErrors(errors);
59	      return;
60	    }
61	
62	    if (password !== confirmPassword) {
63	      toast({
64	        title: "Passwords don't match",
65	        description: "Please make sure both passwords are identical.",
66	        variant: "destructive",
67	      });
68	      return;
69	    }
70	
71	    setIsLoading(true);
72	    const { error } = await supabase.auth.updateUser({ password });
73	    setIsLoading(false);
74	
75	    if (error) {
76	      toast({
77	        title: "Error resetting password",
78	        description: error.message,
79	        variant: "destructive",
80	      });
81	    } else {
82	      toast({
83	        title: "Password updated! 🔒",
84	        description: "Your password has been securely updated.",
85	      });
86	      navigate("/kira");
